toolArgs.file_text:
.catalog-container {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    background-color: #f8f9fa;
    align-self: flex-start;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h5 {
    margin-bottom: 0.5rem;
    font-size: 0.95rem;
    font-weight: 600;
}

.filter-actions {
    margin-top: 1.5rem;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background-color: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
}

.toolbar-sort {
    display: flex;
    align-items: center;
}

.toolbar-sort .form-select {
    width: auto;
    min-width: 180px;
}

.toolbar-info {
    color: #6c757d;
    font-size: 0.9rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
}

.loading-indicator,
.empty-results {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.catalog-pagination {
    margin-top: 2rem;
}

